// Parse the incoming Slack event and decide how to route it
const body = $input.first().json.body || {};
const eventType = body.type || '';

if (eventType === 'url_verification') {
  return [{ json: { route: 'challenge', challenge: body.challenge || '' } }];
}

const event = body.event || {};

if (event.type === 'app_mention') {
  const channelId = event.channel || '';
  const userId = event.user || '';
  const rawText = event.text || '';
  const ts = event.ts || event.event_ts || '';
  const botId = event.bot_id || null;

  // Ignore messages from bots (including ourselves)
  if (botId) {
    return [{ json: { route: 'ignore' } }];
  }

  // Strip the bot mention <@BOTID> from the text
  const userText = rawText.replace(/<@[A-Z0-9]+>/g, '').trim();

  // Route personality by channel ID
  const CHANNEL_MAP = {
    'C0AKJ76RE7R': 'kevin',
    'C0ALCHR9A3B': 'jason',
    'C0AKJ7918JK': 'scaachi',
    'C0AKW7VNHHB': 'christian',
    'C0AKZLG3VFU': 'chidi',
    'C0AKXJSTRV4': 'kevin',
    'C0ALTUECBU0': 'jason',
    'C0AKT93TZAP': 'scaachi',
    'C0AKJ783FF1': 'christian',
    'C0AKJ787K7H': 'chidi'
  };

  const MODEL_MAP = {
    kevin: 'kevin:latest',
    jason: 'jason:latest',
    scaachi: 'scaachi:latest',
    christian: 'christian:latest',
    chidi: 'chidi:latest'
  };

  const agent = CHANNEL_MAP[channelId] || 'kevin';

  return [{ json: {
    route: 'mention',
    channelId,
    userId,
    rawText,
    userText,
    ts,
    agent,
    model: MODEL_MAP[agent]
  } }];
}

// All other events: just ack
return [{ json: { route: 'ignore' } }];

const ollamaResp = $input.first().json;
const parsed = $('Route Event').first().json;

const content = ollamaResp.message?.content || 'No response.';
const MAX = 2800;
const truncated = content.length > MAX
  ? content.slice(0, MAX) + '\n_[truncated]_'
  : content;

return [{ json: {
  channelId: parsed.channelId,
  thread_ts: parsed.ts,
  payload: JSON.stringify({
    channel: parsed.channelId,
    thread_ts: parsed.ts,
    blocks: [
      {
        type: 'context',
        elements: [{ type: 'mrkdwn', text: ':robot_face: *' + parsed.agent + '* responding to <@' + parsed.userId + '>' }]
      },
      {
        type: 'section',
        text: { type: 'mrkdwn', text: truncated }
      }
    ]
  })
}}];
